const ArticleCard: React.FC<ArticleCardProps> = ({ article, isSaved, onToggleSave, language = 'es', textSize = 'base', fontStyle = 'sans', isDarkMode = false, groqApiKey, geminiApiKey, onReadFullText, onExpandStateChange, onUpdateNote, onUpdateVisualAbstract, defaultXrayMode, isSelectionMode, isSelected, onSelect, isDownloaded, onReadOffline, onOpenImmersive, isCompact = false, onUpdateArticle }) => {
  const [showRelated, setShowRelated] = useState(false);
  const [loadingRelated, setLoadingRelated] = useState(false);
  const [relatedArticles, setRelatedArticles] = useState<Article[]>([]);
  const [isExpanded, setIsExpanded] = useState(false);
  const [enhancedData, setEnhancedData] = useState<{ summary: string; tldr: { change: string; population: string } } | null>(null);
  const [isEnhancing, setIsEnhancing] = useState(false);
  const [isGeneratingVisual, setIsGeneratingVisual] = useState(false);
  const [viewMode, setViewMode] = useState<'original' | 'enhanced'>('original');
  const [isXrayMode, setIsXrayMode] = useState(defaultXrayMode || false);
  const [showNoteEditor, setShowNoteEditor] = useState(false);
  const [imageError, setImageError] = useState(false);

  const cardRef = useRef<HTMLDivElement>(null);
  const textContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => { setIsXrayMode(defaultXrayMode || false); }, [defaultXrayMode]);

  const uiLang = language === 'es' ? 'es' : 'en';
  const t = translations[uiLang];
  const highlights = article.highlights || [];

  const wordCount = article.summary.split(/\s+/).length;
  const readTime = Math.max(1, Math.ceil(wordCount / 200));

  // Extract Stats
  const stats = extractStats(article.summary);
  const isSignificant = stats.p && (stats.p.includes('<') || parseFloat(stats.p.split('=')[1] || '1') < 0.05);

  // Badge Configuration
  const badgeConfig = getBadgeConfig(article.category, isDarkMode || false);
  const BadgeIcon = badgeConfig.icon;

  const fontClass = {
      sans: 'font-sans',
      serif: 'font-serif',
      modern: 'font-modern'
  }[fontStyle || 'sans'];

  const handleToggleExpand = () => {
    if (isSelectionMode && onSelect) { onSelect(article); return; }
    if (isCompact) { if (onOpenImmersive) onOpenImmersive(article); return; }
    if (!isExpanded && navigator.vibrate) navigator.vibrate(10);
    const newState = !isExpanded;
    setIsExpanded(newState);
    if (onExpandStateChange) onExpandStateChange(newState);
  };

  const handleEnhance = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!groqApiKey || isEnhancing) return;
    setIsEnhancing(true);
    try {
        const result = await enhanceArticleSummary(article.title, article.summary, language as Language, groqApiKey);
        if (result) {
            setEnhancedData(result);
            setViewMode('enhanced');
            if (onUpdateArticle) {
                onUpdateArticle(article.id, { 
                  summary: result.summary, 
                  clinicalTldr: result.tldr 
                });
            }
        }
    } catch (err) {
        console.error("Enhancement failed", err);
    } finally {
        setIsEnhancing(false);
    }
  };

  const handleGenerateVisual = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (isGeneratingVisual || article.visualAbstract) {
        if (!isExpanded) setIsExpanded(true);
        return;
    }
    setIsGeneratingVisual(true);
    try {
        const result = await generateGeminiVisual(article.title, article.summary, language as Language, geminiApiKey);
        if (result && onUpdateVisualAbstract) {
            onUpdateVisualAbstract(article.id, result);
            setIsExpanded(true);
        }
    } catch (err) {
        console.error("Visual generation failed", err);
    } finally {
        setIsGeneratingVisual(false);
    }
  };

  const handleShare = async () => {
    if (navigator.share) {
      try { await navigator.share({ title: article.title, text: article.summary, url: article.url }); } catch (e) {}
    } else {
      navigator.clipboard.writeText(article.url);
      alert(t.shareCopied);
    }
  };

  const handleCite = (e: React.MouseEvent) => {
    e.stopPropagation();
    const authors = article.authors || 'Unknown Authors';
    const citation = `${authors}. (${article.date}). ${article.title}. ${article.source}. Retrieved from ${article.url}`;
    navigator.clipboard.writeText(citation);
    alert(t.citationCopied);
  };

  const handleEvidenceFlow = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (onReadFullText) onReadFullText(article);
  };

  const handleTitleClick = (e: React.MouseEvent) => {
      e.stopPropagation();
      if (onOpenImmersive) {
          onOpenImmersive(article);
      } else {
          handleEvidenceFlow(e);
      }
  };

  const handleToggleNote = (e: React.MouseEvent) => {
      e.stopPropagation();
      if (isCompact) { if (onOpenImmersive) onOpenImmersive(article); return; }
      if (!isExpanded) setIsExpanded(true);
      setShowNoteEditor(!showNoteEditor);
  };

  const handleShowRelated = async (e: React.MouseEvent) => {
      e.stopPropagation();
      if (showRelated) { setShowRelated(false); return; }
      setShowRelated(true);
      setLoadingRelated(true);
      try {
          const res = await fetchRelatedArticles(article.title, language as Language, geminiApiKey);
          setRelatedArticles(res);
      } catch (err) {} finally { setLoadingRelated(false); }
  };

  const fontSizeClass = { 
    sm: 'text-[11px]', 
    base: 'text-[13px]', 
    lg: 'text-[15px]',
    xl: 'text-[17px]'
  }[textSize];

  // UX Improvement: Increased title size
  const titleSizeClass = isCompact 
    ? "text-lg md:text-xl" 
    : { 
        sm: 'text-lg', 
        base: 'text-xl', 
        lg: 'text-2xl',
        xl: 'text-3xl'
      }[textSize];

  const currentSummary = (viewMode === 'enhanced' && enhancedData) ? enhancedData.summary : article.summary;
  const currentTldr = (viewMode === 'enhanced' && enhancedData) ? enhancedData.tldr : article.clinicalTldr;

  const rawAbstractContent = isXrayMode 
    ? highlightMedicalText(currentSummary, isDarkMode || false)
    : formatAbstract(currentSummary, isDarkMode || false);

  const abstractWithHighlights = applyUserHighlights(rawAbstractContent, highlights, isDarkMode || false);

  if (isCompact) {
      return (
          <motion.div 
            layout
            className={`flex flex-col rounded-[2rem] border transition-all duration-300 group relative overflow-hidden backdrop-blur-3xl saturate-[1.2] shadow-xl ${isDarkMode ? 'bg-[#020617]/80 border-white/5 text-slate-100' : 'bg-white/80 border-slate-200 text-slate-900'}`}
          >
              <div className="p-4 space-y-2">
                  <div className="flex items-center justify-between">
                       <div className="flex items-center gap-2">
                           <span className={`text-[7px] font-black uppercase tracking-widest px-2 py-0.5 rounded-full border ${isDarkMode ? 'bg-blue-500/10 border-blue-500/20 text-blue-400' : 'bg-blue-50 border-blue-100 text-blue-700'}`}>
                               {article.source.split(' ')[0]}
                           </span>
                           {isDownloaded && <WifiOff size={10} className="text-emerald-500" />}
                       </div>
                       <div className="flex items-center gap-2">
                           <CitationHeat score={article.relevanceScore} isDarkMode={isDarkMode} />
                           <button onClick={(e) => { e.stopPropagation(); onToggleSave(article); }} className="text-red-400 hover:text-red-500 p-1" title={t.remove}>
                               <Trash2 size={12} />
                           </button>
                       </div>
                  </div>

                  <h3 onClick={handleTitleClick} className={`${titleSizeClass} ${fontClass} font-bold leading-tight cursor-pointer hover:text-blue-500`}>
                      {article.title}
                  </h3>

                  <div className="flex items-center justify-between gap-4">
                      <div className="flex items-center gap-2 opacity-40 text-[8px] font-black uppercase">
                          <span>{article.date}</span>
                          {article.note && (
                              <span className="flex items-center gap-1 text-amber-500">
                                  <StickyNote size={10} /> {t.personalNote}
                              </span>
                          )}
                      </div>
                      <div className="flex items-center gap-1">
                          <button onClick={() => onOpenImmersive && onOpenImmersive(article)} className={`p-1.5 rounded-full ${isDarkMode ? 'bg-white/5' : 'bg-slate-100'}`}>
                              <BookOpen size={12} className="text-blue-500" />
                          </button>
                          <button onClick={handleEvidenceFlow} className={`p-1.5 rounded-full ${isDarkMode ? 'bg-white/5' : 'bg-slate-100'}`}>
                              {isDownloaded ? <CheckCircle2 size={12} className="text-emerald-500" /> : <ExternalLink size={12} className="text-slate-50" />}
                          </button>
                      </div>
                  </div>
              </div>
          </motion.div>
      );
  }

  return (
    <div ref={cardRef} className={`flex flex-col rounded-[2.2rem] border transition-all duration-500 group relative overflow-hidden backdrop-blur-3xl shadow-xl ${isDarkMode ? 'bg-[#020617]/80 border-white/5 text-slate-100 hover:bg-[#020617]' : 'bg-white/90 border-slate-200 text-slate-900 hover:bg-white'} ${isSelected ? 'ring-4 ring-blue-500 border-transparent' : ''}`}>

      {article.imageUrl && !imageError && (
        <div className="relative w-full h-32 overflow-hidden group-hover:h-36 transition-all duration-700 ease-[cubic-bezier(0.23,1,0.32,1)]">
           <img src={article.imageUrl} alt={article.title} onError={() => setImageError(true)} className="w-full h-full object-cover saturate-[1.1] brightness-[0.9] dark:brightness-[0.7]" />
           <div className={`absolute inset-0 bg-gradient-to-t ${isDarkMode ? 'from-[#020617]' : 'from-white/90'} to-transparent opacity-80`}></div>
        </div>
      )}

      {/* Reduced padding-bottom (pb-16) to ensure the Ribbon is tight to the Action Bar */}
      <div className="p-5 pb-16 space-y-3 relative z-10">
        <div className="flex items-center justify-between">
             <div className="flex items-center gap-1.5 flex-wrap">
                 {/* SEMANTIC BADGE: Color Coded by Article Type */}
                 <span className={`flex items-center gap-1 text-[7px] font-black uppercase tracking-[0.15em] px-2 py-0.5 rounded-full border shadow-sm ${badgeConfig.style}`}>
                     <BadgeIcon size={8} />
                     {article.category}
                 </span>

                 {/* STATS INLINE (N, P, HR) */}
                 {(stats.n || stats.p || stats.ratio) && (
                    <div className="flex items-center gap-1.5 ml-1 animate-in fade-in slide-in-from-left-2">
                        {stats.n && <span className={`text-[9px] font-mono font-bold tracking-tight ${isDarkMode ? 'text-slate-400' : 'text-slate-500'}`}>N={stats.n}</span>}

                        {stats.ratio && (
                            <span className={`text-[9px] font-mono font-bold border-l pl-1.5 ${isDarkMode ? 'border-slate-700 text-blue-300' : 'border-slate-300 text-blue-700'}`}>
                                {stats.ratio}
                            </span>
                        )}

                        {stats.p && (
                            <span className={`text-[9px] font-mono font-bold border-l pl-1.5 ${isDarkMode ? 'border-slate-700' : 'border-slate-300'} ${isSignificant ? 'text-emerald-500' : (isDarkMode ? 'text-slate-500' : 'text-slate-400')}`}>
                                {stats.p}
                            </span>
                        )}
                    </div>
                 )}

                 {isDownloaded && <WifiOff size={9} className="text-emerald-500 ml-0.5" />}
             </div>

             <div className="flex items-center gap-2">
                 {/* Simplified Citation Heat - Only Flame */}
                 <CitationHeat score={article.relevanceScore} isDarkMode={isDarkMode} />

                 <button onClick={(e) => { e.stopPropagation(); handleEvidenceFlow(e); }} className={`p-1 rounded-full transition-all hover:scale-110 active:scale-95 ${isDownloaded ? 'text-emerald-500 bg-emerald-50 dark:bg-emerald-900/20' : (article.isFree ? 'text-emerald-500 bg-emerald-50 dark:bg-emerald-900/20' : 'text-amber-500 bg-amber-50 dark:bg-amber-900/20')}`} title={t.fullTextTip}>
                     {isDownloaded ? <CheckCircle2 size={13} strokeWidth={2.5} /> : (article.isFree ? <Unlock size={13} strokeWidth={2.5} /> : <Lock size={13} strokeWidth={2.5} />)}
                 </button>
             </div>
        </div>

        {/* Metadata Contrast */}
        <div className="flex justify-between items-end border-b border-dashed border-slate-200 dark:border-white/5 pb-2 gap-2">
             <div className="flex flex-col gap-0.5 flex-1 min-w-0">
                <span className={`text-[9px] font-bold uppercase tracking-[0.05em] truncate w-full ${isDarkMode ? 'text-slate-500' : 'text-slate-500'}`}>{article.source}</span>
                <div className="flex items-center gap-2 opacity-50 text-[8px] font-medium uppercase tracking-widest">
                    <span>{article.date}</span>
                    <span>•</span>
                    <span>{readTime} {t.readTime}</span>
                </div>
             </div>
        </div>

        <h3 onClick={handleTitleClick} className={`${titleSizeClass} ${fontClass} font-bold leading-[1.3] tracking-tight transition-colors cursor-pointer hover:text-blue-600 dark:hover:text-blue-400 active:scale-[0.99]`}>
            {article.title}
        </h3>

        {/* CLINICAL TL;DR CAPSULE */}
        {currentTldr && (
            <div className={`mt-3 p-3.5 rounded-2xl border transition-all duration-300 ${isDarkMode ? 'bg-blue-950/20 border-blue-800/40' : 'bg-blue-50/50 border-blue-200 shadow-sm'}`}>
                <div className="flex items-center gap-2 mb-2">
                    <div className="p-1 rounded-md bg-blue-600/10 text-blue-600 dark:text-blue-400">
                        <Activity size={12} />
                    </div>
                    <span className="text-[9px] font-black uppercase tracking-widest opacity-60">{t.tldrTitle}</span>
                </div>
                <div className="space-y-2">
                    <div className="flex gap-2">
                        <span className="text-[10px] font-black text-blue-600 dark:text-blue-400 shrink-0">{t.tldrChange}</span>
                        <p className={`text-[11px] leading-tight font-medium ${isDarkMode ? 'text-slate-200' : 'text-slate-900'}`}>{currentTldr.change}</p>
                    </div>
                    <div className="flex gap-2">
                        <span className="text-[10px] font-black text-indigo-600 dark:text-indigo-400 shrink-0">{t.tldrPopulation}</span>
                        <p className={`text-[11px] leading-tight font-medium ${isDarkMode ? 'text-slate-200' : 'text-slate-900'}`}>{currentTldr.population}</p>
                    </div>
                </div>
            </div>
        )}

        <div className="relative">
          <div onClick={handleToggleExpand} className={`transition-all duration-700 ease-[cubic-bezier(0.23,1,0.32,1)] overflow-hidden relative cursor-pointer ${isExpanded ? 'max-h-[5000px]' : 'max-h-36'}`} style={!isExpanded ? { maskImage: 'linear-gradient(180deg, black 0%, black 70%, transparent 100%)', WebkitMaskImage: 'linear-gradient(180deg, black 0%, black 70%, transparent 100%)' } : {}}>
              <div className={`${fontSizeClass} ${fontClass} leading-relaxed text-justify ${isDarkMode ? 'text-slate-300' : 'text-slate-700'}`}>
                   {isExpanded && (showNoteEditor || article.note) && isSaved && (
                       <div className={`mb-6 mt-2 rounded-2xl p-4 border relative animate-in zoom-in-95 duration-300 ${isDarkMode ? 'bg-amber-900/20 border-amber-800/50' : 'bg-yellow-50 border-yellow-200 shadow-sm'}`} onClick={e => e.stopPropagation()}>
                           <div className="flex items-center gap-2 mb-2 text-amber-500">
                               <StickyNote size={14} />
                               <span className="text-[9px] font-black uppercase tracking-widest">{t.personalNote}</span>
                           </div>
                           <textarea value={article.note || ''} onChange={(e) => onUpdateNote && onUpdateNote(article.id, e.target.value)} placeholder={t.notePlaceholder} className={`w-full bg-transparent outline-none resize-none text-xs leading-relaxed ${isDarkMode ? 'text-amber-200 placeholder-amber-500/50' : 'text-slate-800 placeholder-slate-400'}`} rows={3} />
                       </div>
                   )}

                   {/* ASSOCIATED PUBLICATIONS SECTION */}
                   {article.associatedPublications && article.associatedPublications.length > 0 && isExpanded && (
                       <div className={`mt-4 mb-4 p-4 rounded-2xl border ${isDarkMode ? 'bg-slate-900 border-slate-700' : 'bg-slate-50 border-slate-200'}`} onClick={e => e.stopPropagation()}>
                           <div className="flex items-center gap-2 mb-3">
                               <div className={`p-1.5 rounded-md ${isDarkMode ? 'bg-indigo-500/20 text-indigo-400' : 'bg-indigo-100 text-indigo-600'}`}>
                                   <LinkIcon size={14} />
                               </div>
                               <h4 className="text-[10px] font-black uppercase tracking-widest opacity-70">
                                   {t.assocPubs}
                               </h4>
                           </div>
                           <ul className="space-y-2">
                               {article.associatedPublications.map((pub, idx) => (
                                   <li key={idx} className="flex gap-2 text-[11px] leading-relaxed opacity-80">
                                       <span className="text-blue-500">•</span>
                                       <span dangerouslySetInnerHTML={{ __html: pub.replace(/(PMID:\s*\d+)/, '<span class="font-mono text-[9px] bg-blue-100 dark:bg-blue-900 px-1 rounded">$1</span>') }}></span>
                                   </li>
                                ))}
                           </ul>
                       </div>
                   )}

                   {isExpanded && article.visualAbstract && (
                       <div className="mb-8 mt-4 rounded-3xl overflow-hidden border dark:border-white/5 shadow-2xl">
                           <div className="p-3 bg-slate-100 dark:bg-slate-900 border-b dark:border-white/5 flex items-center justify-between">
                               <span className="text-[8px] font-black uppercase tracking-[0.2em] opacity-50">Visual Summary (AI)</span>
                               <span className="text-[8px] text-blue-500 font-bold">MERMAID.JS</span>
                           </div>
                           <MermaidDiagram chart={article.visualAbstract} isDarkMode={isDarkMode || false} />
                       </div>
                   )}
                   <div ref={textContainerRef} className="select-text pb-0 pt-1">{abstractWithHighlights}</div>
              </div>
          </div>
          {!isExpanded && (
              <div className="absolute bottom-2 left-0 right-0 flex justify-center pointer-events-none z-20">
                  <div className={`p-1 rounded-full shadow-sm animate-bounce ${isDarkMode ? 'bg-slate-800/50 text-slate-400' : 'bg-white/50 text-slate-400 border border-slate-100'}`}><ChevronDown size={12} strokeWidth={2.5} /></div>
              </div>
          )}
        </div>

        {/* REMOVED: SMART EVIDENCE RIBBON */}

      </div>

      {/* Action Bar - Optimized Liquid Glass effect */}
      <div className="absolute bottom-4 left-1/2 -translate-x-1/2 w-[94%] max-w-sm z-30 pointer-events-none">
          <div className={`flex items-center justify-around p-1.5 rounded-full border shadow-2xl backdrop-blur-[32px] saturate-[1.8] pointer-events-auto transition-all hover:scale-[1.02] ${isDarkMode ? 'bg-[#020617]/70 border-white/10 shadow-black/60' : 'bg-white/60 border-white/60 shadow-blue-200/40'}`}>

              {/* Button 1: Bookmark */}
              <button onClick={(e) => { e.stopPropagation(); onToggleSave(article); }} className={`p-2.5 rounded-full transition-all active:scale-90 ${isSaved ? 'text-blue-500 bg-blue-500/20' : 'text-slate-500 hover:bg-black/5 dark:hover:bg-white/10'}`} title={t.library}>
                 {isSaved ? <BookmarkCheck size={16} strokeWidth={2.5} /> : <Bookmark size={16} strokeWidth={2} />}
              </button>

              {/* Button 2: Personal Note */}
              <button onClick={handleToggleNote} disabled={!isSaved} className={`p-2.5 rounded-full transition-all active:scale-90 ${!isSaved ? 'opacity-20 cursor-not-allowed' : (article.note || showNoteEditor ? 'text-amber-500 bg-amber-500/20' : 'text-slate-500 hover:bg-black/5 dark:hover:bg-white/10')}`} title={t.personalNote}>
                  <StickyNote size={16} />
              </button>

              {/* Button 3: Cite */}
              <button onClick={handleCite} className="p-2.5 rounded-full text-slate-500 hover:bg-black/5 dark:hover:bg-white/10 transition-colors" title={t.cite}>
                  <Quote size={16} />
              </button>

              {/* Button 4: Share */}
              <button onClick={(e) => { e.stopPropagation(); handleShare(); }} className="p-2.5 rounded-full text-slate-500 hover:bg-black/5 dark:hover:bg-white/10 transition-colors">
                  <Share2 size={16} />
              </button>

              <div className="h-4 w-px bg-slate-400/20 mx-0.5"></div>

              {/* Button 5: AI Enhance (Groq/Llama 3) */}
              <button onClick={handleEnhance} disabled={isEnhancing} className={`p-2.5 rounded-full transition-all active:scale-90 ${viewMode === 'enhanced' ? 'text-amber-500 bg-amber-500/20' : 'text-slate-500 hover:bg-black/5 dark:hover:bg-white/10'}`} title={t.enhanceGroq}>
                  {isEnhancing ? <Loader2 size={16} className="animate-spin" /> : <Zap size={16} />}
              </button>

              {/* Button 6: Visual Abstract Generation */}
              <button onClick={handleGenerateVisual} disabled={isGeneratingVisual} className={`p-2.5 rounded-full transition-all active:scale-90 ${article.visualAbstract ? 'text-blue-500 bg-blue-500/20' : 'text-slate-500 hover:bg-black/5 dark:hover:bg-white/10'}`} title={t.visualAbstract}>
                  {isGeneratingVisual ? <Loader2 size={16} className="animate-spin" /> : <ImageIcon size={16} />}
              </button>

              {/* Button 7: AI Related Study Search */}
              <button onClick={handleShowRelated} className={`p-2.5 rounded-full transition-all ${showRelated ? 'text-purple-500 bg-purple-500/20' : 'text-slate-500 hover:bg-black/5 dark:hover:bg-white/10'}`} title={t.iaRelated}>
                  <Sparkles size={16} />
              </button>

              {/* Button 8: Evidence Flow (Download Cascade) */}
              <button onClick={handleEvidenceFlow} className={`p-2.5 rounded-full transition-all active:scale-90 text-indigo-500 hover:bg-black/5 dark:hover:bg-white/10`} title={t.fullTextTip}>
                  <Workflow size={16} />
              </button>

          </div>
          <AnimatePresence>
            {showRelated && (
                <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: 10 }} className={`mt-2 p-5 rounded-[2rem] border shadow-2xl backdrop-blur-3xl ${isDarkMode ? 'bg-slate-950/90 border-white/10' : 'bg-white/95 border-slate-200'}`}>
                    <div className="flex justify-between items-center mb-3"><span className="text-[9px] font-black uppercase tracking-[0.2em] opacity-50">{t.iaRelated}</span><button onClick={() => setShowRelated(false)}><X size={12}/></button></div>
                    <div className="space-y-3">
                        {loadingRelated ? <Loader2 className="animate-spin mx-auto text-blue-500" size={16} /> : relatedArticles.map((ra, idx) => (
                            <a key={idx} href={ra.url} target="_blank" rel="noreferrer" className="block p-2 rounded-xl hover:bg-blue-500/5 transition-colors group">
                                <h4 className="text-[11px] font-bold leading-tight group-hover:text-blue-500">{ra.title}</h4>
                                <div className="flex justify-between mt-1 opacity-40 text-[8px] uppercase font-black"><span>{ra.source}</span><span>{ra.relevanceScore}% Match</span></div>
                            </a>
                        ))}
                    </div>
                </motion.div>
            )}
          </AnimatePresence>
      </div>
    </div>
  );
};

export default ArticleCard;

import React, { useEffect, useRef, useState, useCallback } from 'react';
import { X, ChevronUp, Calendar, Users, BookOpen, Highlighter, StickyNote, Plus, Trash2, Check, Copy, Image as ImageIcon, Activity, Type, Link as LinkIcon } from 'lucide-react';
import { Article, FontStyle } from '../types';
import { highlightMedicalText } from '../utils/semanticHighlighter';
import { applyUserHighlights, CitationHeat } from './ArticleCard';
import MermaidDiagram from './MermaidDiagram';
import { motion, AnimatePresence } from 'framer-motion';

interface ImmersiveReaderProps {
  article: Article | null;
  onClose: () => void;
  isDarkMode: boolean;
  onUpdateNote?: (articleId: string, note: string) => void;
  onAddHighlight?: (articleId: string, text: string) => void;
  onRemoveHighlight?: (articleId: string, index: number) => void;
  onUpdateReadingStatus?: (articleId: string, status: 'completed') => void;
  fontStyle?: FontStyle;
}

const ImmersiveReader: React.FC<ImmersiveReaderProps> = ({ 
  article, 
  onClose, 
  isDarkMode, 
  onUpdateNote, 
  onAddHighlight, 
  onRemoveHighlight, 
  onUpdateReadingStatus,
  fontStyle
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [swipeCount, setSwipeCount] = useState(0);
  const touchStartY = useRef(0);
  const [imageError, setImageError] = useState(false);
  const [scrollProgress, setScrollProgress] = useState(0);
  const [activeFont, setActiveFont] = useState<FontStyle>(fontStyle || 'serif');
  const [showFontMenu, setShowFontMenu] = useState(false);

  // Selection State
  const [selection, setSelection] = useState<{ text: string; x: number; y: number } | null>(null);
  const [showNotes, setShowNotes] = useState(false);

  // Auto-Read Logic Refs
  const minTimePassed = useRef(false);
  const hasMarkedRead = useRef(false);

  useEffect(() => {
      if (article) {
          document.body.style.overflow = 'hidden';
          const timer = setTimeout(() => {
              minTimePassed.current = true;
          }, 5000);
          return () => {
              document.body.style.overflow = '';
              clearTimeout(timer);
          };
      } else {
          document.body.style.overflow = '';
      }
  }, [article]);

  useEffect(() => {
      if (fontStyle) setActiveFont(fontStyle);
  }, [fontStyle]);

  const handleMouseUp = useCallback(() => {
    const sel = window.getSelection();
    if (sel && sel.rangeCount > 0 && !sel.isCollapsed) {
        const range = sel.getRangeAt(0);
        const rect = range.getBoundingClientRect();
        const text = sel.toString().trim();

        if (text.length > 0) {
            setSelection({
                text,
                x: rect.left + rect.width / 2,
                y: rect.top - 10
            });
        }
    } else {
        setSelection(null);
    }
  }, []);

  const addSelectionToHighlights = (color: string = 'yellow') => {
    if (selection && article && onAddHighlight) {
        const payload = color === 'yellow' ? selection.text : `${selection.text}:::${color}`;
        onAddHighlight(article.id, payload);
        setSelection(null);
        window.getSelection()?.removeAllRanges();
        if (navigator.vibrate) navigator.vibrate(10);
    }
  };

  const addSelectionToNote = () => {
    if (selection && article && onUpdateNote) {
        const currentNote = article.note || '';
        const newNote = currentNote + (currentNote ? '\n\n' : '') + `> ${selection.text}`;
        onUpdateNote(article.id, newNote);
        setShowNotes(true);
        setSelection(null);
        window.getSelection()?.removeAllRanges();
        if (navigator.vibrate) navigator.vibrate(10);
    }
  };

  const handleTouchStart = (e: React.TouchEvent) => {
      touchStartY.current = e.touches[0].clientY;
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
      if (!containerRef.current) return;

      const { scrollTop, scrollHeight, clientHeight } = containerRef.current;
      const isAtBottom = Math.abs(scrollHeight - clientHeight - scrollTop) < 10;

      const touchEndY = e.changedTouches[0].clientY;
      const deltaY = touchEndY - touchStartY.current;

      if (isAtBottom && deltaY < -50) {
          setSwipeCount(prev => prev + 1);
          if (swipeCount >= 1) {
              onClose();
          } else {
              if (navigator.vibrate) navigator.vibrate(50);
          }
      } else {
          if (!isAtBottom) {
              setSwipeCount(0);
          }
      }
  };

  const handleScroll = (e: React.UIEvent<HTMLDivElement>) => {
      const { scrollTop, scrollHeight, clientHeight } = e.currentTarget;

      // Update Progress Bar
      const totalScroll = scrollHeight - clientHeight;
      const currentProgress = totalScroll > 0 ? (scrollTop / totalScroll) * 100 : 0;
      setScrollProgress(currentProgress);

      const isAtBottom = Math.abs(scrollHeight - clientHeight - scrollTop) < 50;
      if (!isAtBottom) {
          setSwipeCount(0);
      }

      if (!hasMarkedRead.current && minTimePassed.current && article && onUpdateReadingStatus) {
          if (scrollHeight - scrollTop - clientHeight < 200) {
              hasMarkedRead.current = true;
              onUpdateReadingStatus(article.id, 'completed');
              if (navigator.vibrate) navigator.vibrate([10, 30, 10]);
          }
      }
  };

  if (!article) return null;

  const rawAbstractContent = highlightMedicalText(article.summary, isDarkMode);
  const abstractWithHighlights = applyUserHighlights(rawAbstractContent, article.highlights || [], isDarkMode);

  const glassButtonStyle = `p-3 rounded-full transition-all duration-300 backdrop-blur-md ${
    isDarkMode 
      ? 'bg-slate-800/50 text-white hover:bg-slate-700 border border-white/10' 
      : 'bg-white/50 text-slate-900 shadow-sm hover:bg-white border border-white/40'
  }`;

  const fontClass = {
    sans: 'font-sans',
    serif: 'font-serif',
    modern: 'font-modern'
  }[activeFont];

  return (
    <motion.div 
        initial={{ opacity: 0, scale: 0.98, y: 20 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.95, y: 20 }}
        transition={{ duration: 0.4, ease: [0.22, 1, 0.36, 1] }}
        className={`fixed inset-0 z-[100] flex items-center justify-center sm:p-4 md:p-6 backdrop-blur-3xl ${isDarkMode ? 'bg-slate-950/80' : 'bg-slate-200/50'}`}
        onMouseUp={handleMouseUp}
    >
        {/* Floating Selection Toolbar */}
        <AnimatePresence>
            {selection && (
                <motion.div 
                    initial={{ opacity: 0, y: 10, scale: 0.9 }}
                    animate={{ opacity: 1, y: 0, scale: 1 }}
                    exit={{ opacity: 0, y: 10, scale: 0.9 }}
                    style={{ 
                        position: 'fixed', 
                        left: selection.x, 
                        top: selection.y, 
                        transform: 'translate(-50%, -100%)',
                        zIndex: 1000 
                    }}
                    className={`flex items-center gap-1 p-1 rounded-2xl border shadow-2xl backdrop-blur-xl ${isDarkMode ? 'bg-slate-900 border-slate-700' : 'bg-white border-slate-200'}`}
                >
                    <div className="flex gap-1 p-1 border-r border-slate-200 dark:border-slate-700">
                        <button onClick={() => addSelectionToHighlights('yellow')} className="w-6 h-6 rounded-full bg-yellow-400 hover:scale-110 transition-transform"></button>
                        <button onClick={() => addSelectionToHighlights('green')} className="w-6 h-6 rounded-full bg-emerald-400 hover:scale-110 transition-transform"></button>
                        <button onClick={() => addSelectionToHighlights('red')} className="w-6 h-6 rounded-full bg-rose-400 hover:scale-110 transition-transform"></button>
                    </div>
                    <button 
                        onClick={() => addSelectionToHighlights('yellow')}
                        className={`flex items-center gap-2 px-3 py-2 rounded-xl transition-all ${isDarkMode ? 'hover:bg-slate-800 text-slate-300' : 'hover:bg-slate-100 text-slate-600'}`}
                    >
                        <Highlighter size={16} />
                    </button>
                    <div className={`w-px h-4 ${isDarkMode ? 'bg-slate-700' : 'bg-slate-200'}`} />
                    <button 
                        onClick={addSelectionToNote}
                        className={`flex items-center gap-2 px-3 py-2 rounded-xl transition-all ${isDarkMode ? 'hover:bg-slate-800 text-amber-400' : 'hover:bg-slate-100 text-amber-600'}`}
                    >
                        <StickyNote size={16} />
                    </button>
                </motion.div>
            )}
        </AnimatePresence>

        {/* Right Vertical Action Bar (Close, Typography, Notes) */}
        <div className="absolute top-6 right-6 z-[110] flex flex-col gap-3">

            {/* 1. Close Button */}
            <button 
                onClick={onClose} 
                className={glassButtonStyle}
                title="Cerrar"
            >
                <X size={24} />
            </button>

            {/* 2. Typography Button */}
            <div className="relative">
                <button 
                    onClick={() => setShowFontMenu(!showFontMenu)} 
                    className={glassButtonStyle}
                    title="Tipografía"
                >
                    <Type size={24} />
                </button>
                {showFontMenu && (
                    <motion.div 
                        initial={{ opacity: 0, x: 10 }}
                        animate={{ opacity: 1, x: 0 }}
                        className={`absolute top-0 right-full mr-2 p-2 rounded-2xl shadow-xl border w-40 overflow-hidden ${isDarkMode ? 'bg-slate-900 border-white/10' : 'bg-white border-slate-200'}`}
                    >
                        <button 
                            onClick={() => { setActiveFont('serif'); setShowFontMenu(false); }}
                            className={`w-full text-left px-4 py-3 rounded-xl font-serif text-lg hover:bg-black/5 dark:hover:bg-white/5 ${activeFont === 'serif' ? 'text-blue-500' : ''}`}
                        >
                            Serif
                        </button>
                        <button 
                            onClick={() => { setActiveFont('sans'); setShowFontMenu(false); }}
                            className={`w-full text-left px-4 py-3 rounded-xl font-sans text-lg hover:bg-black/5 dark:hover:bg-white/5 ${activeFont === 'sans' ? 'text-blue-500' : ''}`}
                        >
                            Sans
                        </button>
                        <button 
                            onClick={() => { setActiveFont('modern'); setShowFontMenu(false); }}
                            className={`w-full text-left px-4 py-3 rounded-xl font-modern text-lg hover:bg-black/5 dark:hover:bg-white/5 ${activeFont === 'modern' ? 'text-blue-500' : ''}`}
                        >
                            Modern
                        </button>
                    </motion.div>
                )}
            </div>

            {/* 3. Notes Button */}
            <button 
                onClick={() => setShowNotes(!showNotes)} 
                className={`${showNotes ? 'p-3 rounded-full bg-amber-500 text-white shadow-lg transition-all duration-300' : glassButtonStyle}`}
                title="Notas"
            >
                <StickyNote size={24} />
            </button>
        </div>

        <div className="flex h-full w-full max-w-6xl gap-6">
            <div 
                ref={containerRef}
                onTouchStart={handleTouchStart}
                onTouchEnd={handleTouchEnd}
                onScroll={handleScroll}
                className={`flex-1 h-full sm:rounded-[2.5rem] shadow-2xl overflow-y-auto no-scrollbar relative flex flex-col ${isDarkMode ? 'bg-slate-950 text-slate-200 border border-slate-800' : 'bg-white text-slate-900 border border-white/60'}`}
            >
                {/* Reading Progress Bar */}
                <div className="sticky top-0 left-0 right-0 h-1 z-50 bg-transparent">
                    <motion.div 
                        className="h-full bg-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.5)]"
                        style={{ width: `${scrollProgress}%` }}
                        layoutId="readingProgress"
                    />
                </div>

                {/* Header / Masthead */}
                <div className={`relative shrink-0 overflow-hidden min-h-[20rem] md:min-h-[24rem] flex flex-col justify-end p-8 md:p-12 ${isDarkMode ? 'bg-slate-900' : 'bg-slate-50'}`}>
                    <div className={`absolute inset-0 opacity-[0.07] bg-[url('https://www.transparenttextures.com/patterns/cubes.png')] ${isDarkMode ? 'invert' : ''}`}></div>
                    <div className={`absolute inset-0 bg-gradient-to-t ${isDarkMode ? 'from-slate-950 via-slate-900/90 to-slate-900/20' : 'from-white via-white/90 to-blue-50/20'}`}></div>

                    <div className="relative z-10 space-y-4">
                        <div className="flex flex-wrap items-center gap-3 mb-2">
                            <span className={`px-3 py-1 text-[10px] font-black uppercase tracking-[0.2em] rounded-full border ${isDarkMode ? 'bg-blue-500/10 border-blue-500/30 text-blue-300' : 'bg-blue-600 text-white border-blue-600'}`}>
                                {article.category}
                            </span>
                            <div className={`flex items-center gap-2 px-3 py-1 rounded-full border ${isDarkMode ? 'bg-slate-800/50 border-slate-700 text-slate-300' : 'bg-white/60 border-slate-200 text-slate-600'}`}>
                                <CitationHeat score={article.relevanceScore} isDarkMode={isDarkMode} />
                                <span className="text-[10px] font-bold">{article.relevanceScore}% Impact</span>
                            </div>
                        </div>

                        <h1 className={`text-3xl md:text-5xl ${fontClass} font-black tracking-tight leading-[1.1] opacity-95 ${isDarkMode ? 'text-slate-100' : 'text-slate-900'}`}>
                            {article.title}
                        </h1>

                        <div className={`flex items-center gap-2 text-xs font-bold uppercase tracking-wider ${isDarkMode ? 'text-blue-400' : 'text-blue-600'}`}>
                            <Calendar size={14} />
                            <span>{article.date}</span>
                        </div>
                    </div>
                </div>

                {/* Body Content */}
                <div className={`px-6 py-10 md:px-16 md:py-12 max-w-3xl mx-auto w-full flex-1 ${isDarkMode ? 'text-slate-300' : 'text-slate-800'}`}>

                    {/* IMPACT CAPSULE IN IMMERSIVE */}
                    {article.clinicalTldr && (
                        <motion.div 
                          initial={{ opacity: 0, x: -20 }}
                          animate={{ opacity: 1, x: 0 }}
                          className={`mb-12 p-8 rounded-[2.5rem] border-2 transition-all duration-300 ${isDarkMode ? 'bg-blue-900/10 border-blue-500/30' : 'bg-blue-50/50 border-blue-200 shadow-xl'}`}
                        >
                            <div className="flex items-center gap-3 mb-6">
                                <div className="p-2 rounded-xl bg-blue-600 text-white shadow-lg shadow-blue-600/20">
                                    <Activity size={20} />
                                </div>
                                <h2 className="text-sm font-black uppercase tracking-[0.2em] opacity-80">Cápsula de Impacto Clínico</h2>
                            </div>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                <div className="space-y-2">
                                    <span className="text-[10px] font-black text-blue-600 dark:text-blue-400 uppercase tracking-widest">¿Qué cambió?</span>
                                    <p className="text-base font-bold leading-snug">{article.clinicalTldr.change}</p>
                                </div>
                                <div className="space-y-2">
                                    <span className="text-[10px] font-black text-indigo-600 dark:text-indigo-400 uppercase tracking-widest">¿A quién aplica?</span>
                                    <p className="text-base font-bold leading-snug">{article.clinicalTldr.population}</p>
                                </div>
                            </div>
                        </motion.div>
                    )}

                    {/* ASSOCIATED PUBLICATIONS SECTION IN IMMERSIVE */}
                    {article.associatedPublications && article.associatedPublications.length > 0 && (
                        <div className={`mb-12 p-6 rounded-[2rem] border ${isDarkMode ? 'bg-slate-900 border-slate-700' : 'bg-slate-50 border-slate-200'}`}>
                            <div className="flex items-center gap-2 mb-4">
                                <div className={`p-2 rounded-lg ${isDarkMode ? 'bg-indigo-500/20 text-indigo-400' : 'bg-indigo-100 text-indigo-600'}`}>
                                    <LinkIcon size={16} />
                                </div>
                                <h4 className="text-xs font-black uppercase tracking-widest opacity-70">
                                    Publicaciones Derivadas / Resultados
                                </h4>
                            </div>
                            <ul className="space-y-3">
                                {article.associatedPublications.map((pub, idx) => (
                                    <li key={idx} className="flex gap-3 text-sm leading-relaxed opacity-90">
                                        <span className="text-blue-500 mt-1.5">•</span>
                                        <span dangerouslySetInnerHTML={{ __html: pub.replace(/(PMID:\s*\d+)/, '<span class="font-mono text-[10px] bg-blue-100 dark:bg-blue-900 px-1.5 rounded-md mx-1">$1</span>') }}></span>
                                    </li>
                                ))}
                            </ul>
                        </div>
                    )}

                    {/* Art Image in Reader */}
                    {article.imageUrl && !imageError && (
                        <motion.div 
                            initial={{ opacity: 0, y: 20 }}
                            animate={{ opacity: 1, y: 0 }}
                            className="mb-12 rounded-[2rem] overflow-hidden border shadow-xl bg-slate-100 dark:bg-slate-800"
                        >
                            <img 
                                src={article.imageUrl} 
                                alt="Figura principal" 
                                onError={() => setImageError(true)}
                                className="w-full h-auto max-h-[500px] object-contain"
                            />
                            <div className={`px-6 py-3 border-t flex items-center justify-between opacity-50 ${isDarkMode ? 'border-slate-700' : 'border-slate-200'}`}>
                                <div className="flex items-center gap-2">
                                    <ImageIcon size={14} />
                                    <span className="text-[10px] font-black uppercase tracking-widest">Evidencia Visual</span>
                                </div>
                                <span className="text-[9px] font-medium">{article.source}</span>
                            </div>
                        </motion.div>
                    )}

                    <div className="flex items-center gap-3 mb-8">
                        <div className={`p-2 rounded-lg ${isDarkMode ? 'bg-slate-800 text-slate-400' : 'bg-slate-100 text-slate-600'}`}>
                            <BookOpen size={20} />
                        </div>
                        <h2 className={`text-xl md:text-2xl font-sans font-bold leading-tight ${isDarkMode ? 'text-blue-300' : 'text-blue-800'}`}>
                            {article.source}
                        </h2>
                    </div>

                    <div className={`flex items-center gap-2 text-sm mb-10 pb-8 border-b border-dashed ${isDarkMode ? 'text-slate-500 border-slate-800' : 'text-slate-500 border-slate-200'}`}>
                        <Users size={16} />
                        <span className="font-medium italic">{article.authors || 'Unknown Authors'}</span>
                    </div>

                    {article.visualAbstract && (
                        <div className={`mb-12 rounded-3xl border overflow-hidden shadow-sm ${isDarkMode ? 'bg-slate-900/50 border-slate-800' : 'bg-slate-50 border-slate-200'}`}>
                            <div className={`px-6 py-3 border-b text-[10px] font-black uppercase tracking-widest opacity-60 flex items-center justify-between ${isDarkMode ? 'border-slate-800 bg-slate-900' : 'border-slate-200 bg-white'}`}>
                                <span>AI Visual Abstract</span>
                                <span className="text-blue-500">Mermaid.js</span>
                            </div>
                            <MermaidDiagram chart={article.visualAbstract} isDarkMode={isDarkMode} />
                        </div>
                    )}

                    <div className={`text-lg md:text-xl leading-loose ${fontClass} text-justify selection:bg-blue-500/30 dark:selection:bg-blue-500/50 ${isDarkMode ? 'text-slate-200' : 'text-slate-800'}`}>
                        {abstractWithHighlights}
                    </div>

                    {/* Footer Exit Indicator */}
                    <div className="mt-32 pb-16 flex flex-col items-center justify-center space-y-4">
                        <div className={`${glassButtonStyle} ${swipeCount > 0 ? (isDarkMode ? 'bg-blue-600/80 border-blue-400' : 'bg-blue-500/80 text-white border-blue-400 shadow-xl') : ''}`}>
                             <ChevronUp size={28} className={swipeCount > 0 ? "animate-bounce" : ""} />
                        </div>
                        <span className={`text-[10px] font-black uppercase tracking-[0.3em] transition-opacity duration-300 ${swipeCount > 0 ? 'opacity-100' : 'opacity-40'}`}>
                            {swipeCount > 0 ? "Desliza de nuevo para cerrar" : "Fin del Artículo"}
                        </span>
                    </div>
                </div>
            </div>

            {/* Sidebar Notes & Highlights */}
            <AnimatePresence>
                {showNotes && (
                    <motion.div 
                        initial={{ x: 50, opacity: 0 }}
                        animate={{ x: 0, opacity: 1 }}
                        exit={{ x: 50, opacity: 0 }}
                        className={`hidden lg:flex flex-col w-80 h-full p-6 rounded-[2.5rem] border shadow-2xl backdrop-blur-xl ${isDarkMode ? 'bg-slate-900/80 border-slate-800' : 'bg-white/80 border-slate-200'}`}
                    >
                        <div className="flex items-center justify-between mb-6">
                            <h3 className="font-black text-xs uppercase tracking-widest opacity-50">Notas & Hallazgos</h3>
                            <button onClick={() => setShowNotes(false)} className={glassButtonStyle}><X size={16}/></button>
                        </div>

                        <div className="flex-1 overflow-y-auto space-y-6 no-scrollbar">
                            <section>
                                <div className="flex items-center gap-2 mb-3 text-amber-500">
                                    <StickyNote size={14} />
                                    <span className="text-[10px] font-black uppercase tracking-widest">Anotaciones</span>
                                </div>
                                <textarea 
                                    value={article.note || ''}
                                    onChange={(e) => onUpdateNote && onUpdateNote(article.id, e.target.value)}
                                    placeholder="Escribe tus observaciones clínicas..."
                                    className={`w-full h-40 bg-transparent outline-none resize-none text-sm leading-relaxed ${isDarkMode ? 'text-amber-200' : 'text-slate-800'}`}
                                />
                            </section>

                            <section>
                                <div className="flex items-center gap-2 mb-3 text-blue-500">
                                    <Highlighter size={14} />
                                    <span className="text-[10px] font-black uppercase tracking-widest">Resaltados ({article.highlights?.length || 0})</span>
                                </div>
                                <div className="space-y-3">
                                    {article.highlights?.map((h, i) => {
                                        const [text] = h.includes(':::') ? h.split(':::') : [h];
                                        return (
                                            <div key={i} className={`p-3 rounded-xl text-xs relative group ${isDarkMode ? 'bg-slate-800/50' : 'bg-slate-50'}`}>
                                                <p className="italic line-clamp-3">"{text}"</p>
                                                <button 
                                                    onClick={() => onRemoveHighlight && onRemoveHighlight(article.id, i)}
                                                    className="absolute top-1 right-1 p-1 opacity-0 group-hover:opacity-100 transition-opacity text-red-500"
                                                >
                                                    <Trash2 size={12} />
                                                </button>
                                            </div>
                                        );
                                    })}
                                    {(!article.highlights || article.highlights.length === 0) && (
                                        <p className="text-[10px] opacity-40 italic">Selecciona texto para resaltar</p>
                                    )}
                                </div>
                            </section>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </div>

        {/* Mobile Notes Sheet */}
        <AnimatePresence>
            {showNotes && (
                <motion.div 
                    initial={{ y: '100%' }}
                    animate={{ y: 0 }}
                    exit={{ y: '100%' }}
                    className={`fixed inset-x-0 bottom-0 z-[120] p-6 lg:hidden rounded-t-[3rem] shadow-2xl border-t backdrop-blur-xl ${isDarkMode ? 'bg-slate-900/90 border-slate-800' : 'bg-white/90 border-slate-200'}`}
                >
                    <div className="w-12 h-1.5 bg-slate-400/20 rounded-full mx-auto mb-6" />
                    <div className="flex items-center justify-between mb-4">
                        <h3 className="font-black text-xs uppercase tracking-widest opacity-50">Notas Clínicas</h3>
                        <button onClick={() => setShowNotes(false)} className={glassButtonStyle}><X size={20}/></button>
                    </div>
                    <textarea 
                        autoFocus
                        value={article.note || ''}
                        onChange={(e) => onUpdateNote && onUpdateNote(article.id, e.target.value)}
                        placeholder="Observaciones..."
                        className={`w-full h-32 bg-transparent outline-none resize-none text-base leading-relaxed ${isDarkMode ? 'text-amber-200' : 'text-slate-800'}`}
                    />
                </motion.div>
            )}
        </AnimatePresence>
    </motion.div>
  );
};

export default ImmersiveReader;
